from itertools import cycle

def custom_decode(data, salt='3z6kka4NTou9m3De', magic=2030):
    result = bytearray()
    for b, salt_char in zip(data, cycle(salt.encode())):
        result.append((b - salt_char - magic) % 256)
    return bytes(result)


